INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-00274', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列有關望遠鏡（telescope）的敘述，何者錯誤？', '["伽利略望遠鏡（Galileantelescope）是最常使用於低視力的望遠鏡，其影像是正立的", "克普勒望遠鏡（Kepleriantelescope）使用兩個凸透鏡組合成一倒立的影像，再用稜鏡轉成正向以便使用", "克普勒望遠鏡（Kepleriantelescope）比起伽利略望遠鏡（Galileantelescope）更能提供較大的視野範圍", "望遠鏡上面的刻記為8 20,7.5。其可能代表的涵意為放大倍率八倍，目鏡直徑20mm，以及視野7.5度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00275', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '許多低視力病人有眩光（glare）的困擾，有關眩光的敘述，下列何者錯誤？', '["原因包含角膜水腫、角×膜結痂、虹膜缺損、白內障", "評估方法包含測量視力及對比敏感度（contrastsensitivity），測量狀態分為有強光直射病人及正常狀態下", "檢視病人目前使用的照明種類是否容易導致眩光，若為鹵素燈或螢光燈較不會造成眩光", "有時並非照明燈的種類所造成，而是擺放燈或投射的方向導致"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00276', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '老年人使用雙光式望遠鏡（bioptictelescope）輔具時，下列敘述何者錯誤？', '["望遠鏡頭通常可裝設於單眼或雙眼", "望遠鏡頭通常都裝設在鏡框的下方位置", "患者大部分的時間都使用非望遠鏡的部分觀看", "使用望遠鏡時，都是在進行短暫、定點注視的視覺工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00277', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '已處理過白內障（pseudophakic）的68歲珠寶商老張需要等效鏡度+15D處理鑲鑽作業，你認為老張要用 下列那種放大系統來達到放大率需求並兼顧肩頸健康？', '["使用+16D的microscope「眼鏡型放大鏡」", "使用5 並附有+3.00D閱讀帽的loupe「近用望遠鏡」", "使用2.5 並附有+6.00D閱讀帽的loupe", "使用5×立式放大鏡搭配+2.50D近用加入度眼鏡 × ×"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00278', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關視覺損傷患者的心理層面及復健，下列敘述何者正確？', '["視覺損傷發生的年齡與後續的失能（disability）有重要的相關性，一般而言，後天或是老年的視覺損傷 較容易適應，因為他們對視覺環境比較熟悉", "視覺損傷患者不像一般的重大傷病的患者，會經歷幾個心理階段，包括拒絕接受，憤怒，憂鬱等", "通常患者在視覺損傷初期常不了解自己的病況，復健團隊需要提供正確的資訊以及溝通合理的期待以訂 定復健目標", "復健團隊不需要提供友善、安全的環境，復健動機要靠視覺損傷患者自行覺醒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00279', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列關於鏡片式放大鏡（spectaclemagnifiers）的敘述，何者正確？', '["一定要配在鏡片的正中心", "使用這樣的鏡片，病人一定會喪失雙眼同時視物（binocularsinglevision）的能力", "可空出雙手來做其他事", "與同倍率的放大鏡相比，鏡片式放大鏡的工作距離較長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00280', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '關於低視力病人的敘述，下列何者正確？', '["導盲杖必須經由適當的訓練才能夠使用", "所有低視力病人皆需學習點字才能與他人溝通", "高亮度的環境適合所有低視力病人", "照顧低視力病人僅需驗光師即可，不需要多團隊合作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00281', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '關於披衣菌角膜炎之敘述，下列何者錯誤？', '["所有的披衣菌角膜炎都會造成嚴重且不可挽回之視力損害、甚至視力喪失", "角膜上皮下圓形混濁，又稱砂眼膿疱", "Herbert赫伯氏凹孔", "角膜微血管翳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00282', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關眼翳（Pterygium）之敘述，下列何者正確？①是病毒感染引起  ②若影響視力及外觀，可手術切除', '["嚴重時可引起角膜散光的變化", "有轉變成惡性腫瘤的高度可能", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00283', 'optometrist', 'optometrist-moex-113-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關上輪部角結膜炎的敘述，下列何者錯誤？', '["上輪部角結膜增厚角質化", "可以硝酸銀燒灼患部治療", "利用螢光染色可幫助診斷", "約一半的病人有甲狀腺異常"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "7ba1258dd15b", "answer_pdf_sha1": "0715bab7ee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
